/*
 * Called after reboot to confirm the new firmware is working.
 * If not called within the watchdog timeout, the bootloader
 * will roll back to the previous firmware.
 */
fw_error_t firmware_confirm_update(void)
{
    const esp_partition_t *running = esp_ota_get_running_partition();
    esp_ota_img_states_t ota_state;

    esp_err_t err = esp_ota_get_state_partition(running, &ota_state);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Could not get OTA state: %s", esp_err_to_name(err));
        return FW_OK;  /* Not an OTA partition, nothing to confirm */
    }

    if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Confirming new firmware is operational");

        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to confirm firmware: %s", esp_err_to_name(err));
            return FW_ERR_ROLLBACK;
        }

        const esp_app_desc_t *app = esp_ota_get_app_description();
        ESP_LOGI(TAG, "Firmware %s confirmed and marked as valid", app ? app->version : "unknown");
    }

    return FW_OK;
}

/*
 * Trigger a rollback to the previous firmware version.
 */
fw_error_t firmware_rollback(void)
{
    ESP_LOGW(TAG, "Initiating firmware rollback");

    esp_err_t err = esp_ota_mark_app_invalid_rollback_and_reboot();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Rollback failed: %s", esp_err_to_name(err));
        return FW_ERR_ROLLBACK;
    }

    /* Should not reach here - device reboots */
    return FW_OK;
}

/*
 * Example usage / entry point for update task.
 */
void firmware_update_task(void *pvParameters)
{
    /* First, confirm current firmware if pending */
    firmware_confirm_update();

    fw_update_config_t config = {0};
    strncpy(config.url, "https://updates.example.com/firmware/v2.1.0/esp32_smarthome.bin",
            sizeof(config.url) - 1);
    config.url[sizeof(config.url) - 1] = '\0';
    strncpy(config.expected_version, "2.1.0", sizeof(config.expected_version) - 1);
    config.force_update = false;

    fw_error_t result = firmware_update(&config);

    if (result != FW_OK) {
        ESP_LOGE(TAG, "Firmware update failed with error: %d", result);
    }

    vTaskDelete(NULL);
}